.darma-loader-uiverse-white-tower-bounce { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-white-tower-bounce__lines-loader {
  display: flex;
  align-items: center;
  gap: 10px;
}

.darma-loader-uiverse-white-tower-bounce__line {
width: 8px;
height: 58px;
background-color: var(--loader-color, #ffffff);
animation: darma-loader-uiverse-white-tower-bounce-bounce 1.5s infinite ease-in-out;
box-shadow: 0 4px 8px rgba(0, 0, 0, 0.3); /* Box shadow added */
}

/* Create staggered bouncing effect */
.darma-loader-uiverse-white-tower-bounce__line:nth-child(2) {
animation-delay: 0.3s;
}

.darma-loader-uiverse-white-tower-bounce__line:nth-child(3) {
animation-delay: 0.6s;
}

.darma-loader-uiverse-white-tower-bounce__line:nth-child(5) {
animation-delay: 1.2s;
}

/* Bounce Keyframes */
@keyframes darma-loader-uiverse-white-tower-bounce-bounce {
0%,
20%,
50%,
80%,
100% {
transform: translateY(0);
}
40% {
transform: translateY(-30px);
}
60% {
transform: translateY(-15px);
}
}

